import React from 'react';
import {createStackNavigator} from '@react-navigation/stack';
import HomeScreen from '../features/home/HomeScreen';

export type MyMiniApp2StackParamList = {
  MyMiniApp2Home: undefined;
};

const Stack = createStackNavigator<MyMiniApp2StackParamList>();

const MainNavigator = () => {
  return (
    <Stack.Navigator>
      <Stack.Screen
        name="MyMiniApp2Home"
        component={HomeScreen}
        options={{title: 'MyMiniApp2'}}
      />
    </Stack.Navigator>
  );
};

export default MainNavigator;
